const property = $('New Property Ready Webhook').first().json;
const buyers = $('Fetch Buyers Registry').first().json.buyers || [];
const matched = buyers.filter(b => {
  const markets = b.markets || [];
  const criteria = b.criteria || {};
  const marketMatch = markets.length === 0 || markets.some(m => (property.city || '').toLowerCase().includes(m.toLowerCase()));
  const priceMatch = !criteria.max_price || property.asking_price <= criteria.max_price;
  const bedsMatch = !criteria.min_beds || property.beds >= criteria.min_beds;
  return marketMatch && priceMatch && bedsMatch;
});
const sorted = matched.sort((a, b) => (b.buyer_score || 0) - (a.buyer_score || 0)).slice(0, 10);
return sorted.map(b => ({ json: { ...b, property } }));

